srcDoc.css:
@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
* {
  box-sizing: border-box;
  font-family: "Figtree", sans-serif;
  margin: 0;
  padding: 0;
}

.card {
  background: #fff;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 10px;
  overflow: hidden;
  margin-bottom: 12px;
}

.card-header {
  padding: 14px 16px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  flex-wrap: wrap;
}

.card-title {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.header-right {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-wrap: wrap;
}

.btn {
  font-family: "Figtree", sans-serif;
  font-size: 12px;
  font-weight: 700;
  padding: 0 16px;
  height: 34px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
  white-space: nowrap;
}

.btn-primary {
  background: #A3E851;
  color: #05042E;
}

.btn-primary:hover {
  background: #5DC987;
}

.btn-secondary {
  background: rgba(5, 4, 46, 0.06);
  color: #05042E;
}

.btn-secondary:hover {
  background: rgba(5, 4, 46, 0.1);
}

.btn-close-pallet {
  background: #FAEEDA;
  color: #633806;
}

.btn-close-pallet:hover {
  background: #f5deb0;
}

.btn-danger {
  background: #fee2e2;
  color: #991b1b;
}

.btn-sm {
  font-size: 11px;
  font-weight: 700;
  padding: 4px 10px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
  margin-right: 4px;
  font-family: "Figtree", sans-serif;
}

.btn-edit {
  background: #E3EFF6;
  color: #1B4F6C;
}

.btn-view {
  background: #A3E851;
  color: #05042E;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th {
  text-align: left;
  padding: 9px 12px;
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
  white-space: nowrap;
}

td {
  padding: 10px 12px;
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.06);
  vertical-align: middle;
}

tr:last-child td {
  border-bottom: none;
}

tr:hover td {
  background: #f9f8f6;
}

.empty {
  text-align: center;
  padding: 24px;
  color: #888780;
  font-size: 12px;
  font-weight: 500;
}

.waste-id {
  font-family: monospace;
  font-size: 12px;
  font-weight: 700;
  color: #085041;
  background: #E1F5EE;
  padding: 2px 8px;
  border-radius: 4px;
}

.badge {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  padding: 3px 10px;
  border-radius: 20px;
  white-space: nowrap;
  display: inline-block;
}

.badge-open {
  background: #E3EFF6;
  color: #1B4F6C;
}

.badge-closed {
  background: #FAEEDA;
  color: #633806;
}

.badge-collected {
  background: #E1F5EE;
  color: #085041;
}

.waste-type-badge {
  background: rgba(5, 4, 46, 0.06);
  color: #05042E;
  font-size: 10px;
  font-weight: 700;
  padding: 2px 8px;
  border-radius: 20px;
}

.section-subtitle {
  font-size: 11px;
  font-weight: 700;
  color: #05042E;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  padding-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.section-count {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  background: rgba(5, 4, 46, 0.06);
  padding: 2px 8px;
  border-radius: 20px;
}

.meta-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 0;
}

.meta-item {
  padding: 14px 16px;
  border-right: 0.5px solid rgba(0, 0, 0, 0.06);
}

.meta-item:last-child {
  border-right: none;
}

.meta-label {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 4px;
}

.meta-value {
  font-size: 13px;
  font-weight: 700;
  color: #05042E;
}

.meta-value.muted {
  color: #888780;
  font-weight: 500;
}

.form-panel {
  display: none;
  padding: 16px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
  background: rgba(5, 4, 46, 0.02);
}

.form-panel.open {
  display: block;
}

.form-title {
  font-size: 13px;
  font-weight: 700;
  color: #05042E;
  margin-bottom: 12px;
}

.form-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.form-group.full {
  grid-column: 1/-1;
}

label {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

input, select, textarea {
  font-family: "Figtree", sans-serif;
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  padding: 8px 10px;
  outline: none;
  background: #fff;
  width: 100%;
}

input:focus, select:focus, textarea:focus {
  border-color: #469BC0;
}

textarea {
  resize: vertical;
  min-height: 50px;
  font-weight: 500;
}

.form-actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
  margin-top: 14px;
}

.type-tabs {
  display: flex;
  gap: 6px;
  margin-bottom: 14px;
}

.type-tab {
  font-size: 11px;
  font-weight: 700;
  padding: 5px 14px;
  border-radius: 20px;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  cursor: pointer;
  background: #fff;
  color: #888780;
  font-family: "Figtree", sans-serif;
}

.type-tab.active {
  background: #05042E;
  color: #A3E851;
  border-color: #05042E;
}

.search-results {
  margin-top: 8px;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 6px;
  overflow: hidden;
  display: none;
  max-height: 200px;
  overflow-y: auto;
}

.search-result-row {
  padding: 8px 12px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.06);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-size: 12px;
}

.search-result-row:last-child {
  border-bottom: none;
}

.search-result-row:hover {
  background: #f9f8f6;
}

.result-ref {
  font-family: monospace;
  font-size: 11px;
  color: #085041;
  background: #E1F5EE;
  padding: 1px 6px;
  border-radius: 3px;
  margin-right: 8px;
}

.selected-item {
  background: #E1F5EE;
  border: 0.5px solid rgba(163, 232, 81, 0.4);
  border-radius: 6px;
  padding: 8px 12px;
  margin-top: 8px;
  display: none;
  font-size: 12px;
  font-weight: 600;
  color: #085041;
}

.item-type {
  font-size: 10px;
  font-weight: 700;
  padding: 2px 8px;
  border-radius: 20px;
}

.type-asset {
  background: #E3EFF6;
  color: #1B4F6C;
}

.type-part {
  background: #E1F5EE;
  color: #085041;
}

.type-freetext {
  background: rgba(5, 4, 46, 0.06);
  color: #05042E;
}

