var currentView = 'list'; // 'list' | 'detail'
var pallets = [];
var vendors = [];
var items = [];
var selectedPallet = {};
var editingId = null;
var currentType = 'freetext';
var selectedAsset = null;
var selectedPart = null;
function fmt(d) {
  if (!d) return '—';
  var dt = new Date(d);
  if (isNaN(dt.getTime())) return String(d);
  return dt.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function statusBadgeClass(s) {
  var cls = {
    open: 'badge-open',
    closed: 'badge-closed',
    collected: 'badge-collected'
  };
  return cls[s] || 'badge-open';
}
function wasteTypeLabel(t) {
  var map = {
    mixed_electrical: 'Mixed Electrical',
    hazardous: 'Hazardous',
    battery: 'Battery',
    other: 'Other'
  };
  return map[t] || t || '—';
}
function escHtml(str) {
  if (str === null || str === undefined) return '';
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
var formOpen = false;
function groupByStatus(list) {
  var groups = {
    open: [],
    closed: [],
    collected: []
  };
  list.forEach(function (p) {
    var s = p.status || 'open';
    if (!groups[s]) groups[s] = [];
    groups[s].push(p);
  });
  return groups;
}
function renderPalletTable(rows) {
  if (!rows.length) return '<div class="empty">None</div>';
  var rowsHtml = rows.map(function (p) {
    return '<tr>' + '<td><span class="waste-id">' + escHtml(p.waste_id || '—') + '</span></td>' + '<td><span class="waste-type-badge">' + escHtml(wasteTypeLabel(p.waste_type)) + '</span></td>' + '<td>' + (p.vendor_name ? escHtml(p.vendor_name) : '<span style="color:#888780">—</span>') + '</td>' + '<td>' + (p.item_count || 0) + '</td>' + '<td>' + (p.weight_kg ? p.weight_kg + ' kg' : '—') + '</td>' + '<td style="font-size:11px">' + fmt(p.created_date) + '</td>' + '<td style="font-size:11px">' + fmt(p.collection_date) + '</td>' + '<td>' + '<button class="btn-sm btn-edit" data-pallet-id="' + p.pallet_id + '" data-action="edit">Edit</button>' + '<button class="btn-sm btn-view" data-pallet-id="' + p.pallet_id + '" data-action="view">View</button>' + '</td>' + '</tr>';
  }).join('');
  return '<table><thead><tr><th>Waste ID</th><th>Waste Type</th><th>Vendor</th><th>Items</th><th>Weight (kg)</th><th>Created</th><th>Collection Date</th><th></th></tr></thead><tbody>' + rowsHtml + '</tbody></table>';
}
function renderFormPanel() {
  return '<div class="form-panel open" id="form_panel">' + '<div class="form-title" id="form_title">' + (editingId ? 'Edit Pallet' : 'New Waste Pallet') + '</div>' + '<div class="form-grid">' + '<div class="form-group full"><label>Waste Type</label><select id="f_waste_type">' + '<option value="mixed_electrical">Mixed Electrical</option>' + '<option value="hazardous">Hazardous</option>' + '<option value="battery">Battery</option>' + '<option value="other">Other</option>' + '</select></div>' + '<div class="form-group full" id="f_vendor_group" style="display:none"><label>Downstream Vendor</label><select id="f_vendor"></select></div>' + '<div class="form-group" id="f_weight_group" style="display:none"><label>Weight (kg)</label><input type="number" id="f_weight" placeholder="0.00" step="0.01" min="0"/></div>' + '<div class="form-group" id="f_collection_group" style="display:none"><label>Collection Date</label><input type="date" id="f_collection_date"/></div>' + '<div class="form-group" id="f_status_group" style="display:none"><label>Status</label><select id="f_status">' + '<option value="open">Open</option><option value="closed">Closed</option><option value="collected">Collected</option>' + '</select></div>' + '<div class="form-group full"><label>Notes</label><textarea id="f_notes"></textarea></div>' + '</div>' + '<div class="form-actions"><button class="btn btn-secondary" id="btn_cancel_form">Cancel</button><button class="btn btn-primary" id="btn_save_pallet">Save</button></div>' + '</div>';
}

// ---------- LIST VIEW ----------
function renderListView() {
  if (formOpen) {
    return '<div class="card">' + '<div class="card-header"><span class="card-title">Waste Pallets</span></div>' + renderFormPanel() + '</div>';
  }
  var groups = groupByStatus(pallets);
  return '<div class="card">' + '<div class="card-header"><span class="card-title">Waste Pallets</span>' + '<button class="btn btn-primary" id="btn_new_pallet">+ New Pallet</button></div>' + '<div style="padding:14px 16px 0;">' + '<div class="section-subtitle">Open <span class="section-count">' + groups.open.length + '</span></div>' + '</div>' + renderPalletTable(groups.open) + '<div style="padding:14px 16px 0;">' + '<div class="section-subtitle">Closed <span class="section-count">' + groups.closed.length + '</span></div>' + '</div>' + renderPalletTable(groups.closed) + '<div style="padding:14px 16px 0;">' + '<div class="section-subtitle">Collected <span class="section-count">' + groups.collected.length + '</span></div>' + '</div>' + renderPalletTable(groups.collected) + '</div>';
}
function populateVendors(sel, selectedId) {
  if (!sel) return;
  sel.innerHTML = '<option value="">Select vendor...</option>' + vendors.map(function (v) {
    return '<option value="' + v.vendor_id + '"' + (selectedId == v.vendor_id ? ' selected' : '') + '>' + escHtml(v.name) + '</option>';
  }).join('');
}
function showEditFields(show) {
  ['f_vendor_group', 'f_weight_group', 'f_collection_group', 'f_status_group'].forEach(function (id) {
    var el = document.getElementById(id);
    if (el) el.style.display = show ? 'flex' : 'none';
  });
}
function wireListEvents() {
  var newBtn = document.getElementById('btn_new_pallet');
  if (newBtn) newBtn.addEventListener('click', function () {
    editingId = null;
    formOpen = true;
    renderAll(appsmith.model);
  });
  var cancelBtn = document.getElementById('btn_cancel_form');
  if (cancelBtn) cancelBtn.addEventListener('click', function () {
    formOpen = false;
    editingId = null;
    renderAll(appsmith.model);
  });
  if (editingId !== null) {
    var p = pallets.find(function (x) {
      return x.pallet_id === editingId;
    });
    if (p) {
      document.getElementById('form_title').textContent = 'Edit — ' + p.waste_id;
      document.getElementById('f_waste_type').value = p.waste_type || 'mixed_electrical';
      document.getElementById('f_notes').value = p.notes || '';
      document.getElementById('f_weight').value = p.weight_kg || '';
      document.getElementById('f_collection_date').value = p.collection_date ? p.collection_date.split('T')[0] : '';
      document.getElementById('f_status').value = p.status || 'open';
      showEditFields(true);
      populateVendors(document.getElementById('f_vendor'), p.vendor_id);
    }
  } else if (formOpen) {
    document.getElementById('f_waste_type').value = 'mixed_electrical';
    document.getElementById('f_notes').value = '';
    document.getElementById('f_weight').value = '';
    document.getElementById('f_collection_date').value = '';
    document.getElementById('f_status').value = 'open';
    showEditFields(false);
  }
  var saveBtn = document.getElementById('btn_save_pallet');
  if (saveBtn) saveBtn.addEventListener('click', function () {
    var vid = document.getElementById('f_vendor').value;
    var w = document.getElementById('f_weight').value;
    var cd = document.getElementById('f_collection_date').value;
    appsmith.updateModel({
      pallet_id: editingId,
      pallet_waste_type: document.getElementById('f_waste_type').value,
      pallet_vendor_id: vid ? parseInt(vid) : null,
      pallet_weight: w ? parseFloat(w) : null,
      pallet_collection_date: cd || null,
      pallet_status: document.getElementById('f_status').value || 'open',
      pallet_notes: document.getElementById('f_notes').value,
      is_edit: editingId !== null
    });
    appsmith.triggerEvent('onSavePallet');
    formOpen = false;
    editingId = null;
  });
  document.querySelectorAll('[data-action="edit"]').forEach(function (btn) {
    btn.addEventListener('click', function () {
      editingId = Number(this.dataset.palletId);
      formOpen = true;
      renderAll(appsmith.model);
    });
  });
  document.querySelectorAll('[data-action="view"]').forEach(function (btn) {
    btn.addEventListener('click', function () {
      var p = pallets.find(function (x) {
        return x.pallet_id === Number(this.dataset.palletId);
      }.bind(this));
      if (!p) return;
      selectedPallet = p;
      currentView = 'detail';
      appsmith.updateModel({
        selectedPalletId: p.pallet_id
      });
      appsmith.triggerEvent('onSelectPallet');
      renderAll(appsmith.model);
    }.bind(btn));
  });
}

// ---------- DETAIL VIEW ----------
function renderDetailView() {
  var p = selectedPallet;
  var itemsRows = !items.length ? '<tr><td colspan="7" class="empty">No items on this pallet yet</td></tr>' : items.map(function (it) {
    var typeClass = {
      asset: 'type-asset',
      part: 'type-part',
      freetext: 'type-freetext'
    };
    var ref = it.asset_ref ? '<span class="result-ref">' + escHtml(it.asset_ref) + '</span>' : it.part_ref ? '<span class="result-ref">' + escHtml(it.part_ref) + '</span>' : '—';
    var desc = it.description || [it.make_name, it.model_name].filter(Boolean).join(' ') || it.part_type || '' || '—';
    return '<tr>' + '<td><span class="item-type ' + (typeClass[it.item_type] || 'type-freetext') + '">' + escHtml(it.item_type) + '</span></td>' + '<td>' + ref + '</td>' + '<td>' + escHtml(desc) + '</td>' + '<td>' + (it.quantity || 1) + '</td>' + '<td style="font-size:11px">' + escHtml(it.added_by || '—') + '</td>' + '<td style="font-size:11px">' + fmt(it.added_date) + '</td>' + '<td><button class="btn-sm btn-danger" data-item-id="' + it.item_id + '" data-action="delete-item">Remove</button></td>' + '</tr>';
  }).join('');
  return '<div class="card">' + '<div class="card-header">' + '<span class="card-title">Waste Pallet</span>' + '<div class="header-right">' + '<span class="waste-id">' + escHtml(p.waste_id || '—') + '</span>' + '<span class="waste-type-badge">' + escHtml(wasteTypeLabel(p.waste_type)) + '</span>' + '<span class="badge ' + statusBadgeClass(p.status) + '">' + escHtml(p.status || 'open') + '</span>' + '<button class="btn btn-close-pallet" id="btn_close_pallet">Close Pallet</button>' + '<button class="btn btn-secondary" id="btn_back">← Back</button>' + '</div>' + '</div>' + '<div class="meta-grid">' + '<div class="meta-item"><div class="meta-label">Vendor</div><div class="meta-value' + (p.vendor_name ? '' : ' muted') + '">' + escHtml(p.vendor_name || 'No vendor assigned') + '</div></div>' + '<div class="meta-item"><div class="meta-label">Weight</div><div class="meta-value">' + (p.weight_kg ? p.weight_kg + ' kg' : '—') + '</div></div>' + '<div class="meta-item"><div class="meta-label">Created</div><div class="meta-value">' + fmt(p.created_date) + '</div></div>' + '<div class="meta-item"><div class="meta-label">Collection Date</div><div class="meta-value">' + fmt(p.collection_date) + '</div></div>' + '</div>' + '</div>' + '<div class="card">' + '<div class="card-header"><span class="card-title">Items</span><button class="btn btn-primary" id="btn_add_item">+ Add Item</button></div>' + '<div class="form-panel" id="add_form">' + '<div class="form-title">Add Item</div>' + '<div class="type-tabs">' + '<button class="type-tab active" data-type="freetext">Free Text</button>' + '<button class="type-tab" data-type="asset">Asset</button>' + '<button class="type-tab" data-type="part">Part</button>' + '</div>' + '<div id="freetext_fields"><div class="form-grid">' + '<div class="form-group full"><label>Description</label><input type="text" id="f_description" placeholder="e.g. Mixed cables, power adapters"/></div>' + '<div class="form-group"><label>Quantity</label><input type="number" id="f_quantity" value="1" min="1"/></div>' + '<div class="form-group"><label>Notes</label><input type="text" id="f_item_notes"/></div>' + '</div></div>' + '<div id="asset_fields" style="display:none">' + '<div class="form-group full"><label>Search Asset</label><input type="text" id="f_asset_search" placeholder="Asset ref or serial..."/>' + '<div class="search-results" id="asset_results"></div><div class="selected-item" id="selected_asset_display"></div></div>' + '</div>' + '<div id="part_fields" style="display:none">' + '<div class="form-group full"><label>Search Part</label><input type="text" id="f_part_search" placeholder="Part ref or serial..."/>' + '<div class="search-results" id="part_results"></div><div class="selected-item" id="selected_part_display"></div></div>' + '</div>' + '<div class="form-actions"><button class="btn btn-secondary" id="btn_cancel_item">Cancel</button><button class="btn btn-primary" id="btn_save_item">Add to Pallet</button></div>' + '</div>' + '<table><thead><tr><th>Type</th><th>Reference</th><th>Description</th><th>Qty</th><th>Added By</th><th>Date</th><th></th></tr></thead>' + '<tbody>' + itemsRows + '</tbody></table>' + '</div>';
}
function setType(type) {
  currentType = type;
  ['freetext', 'asset', 'part'].forEach(function (t) {
    var el = document.getElementById(t + '_fields');
    if (el) el.style.display = t === type ? 'block' : 'none';
  });
  document.querySelectorAll('.type-tab').forEach(function (btn) {
    btn.classList.toggle('active', btn.dataset.type === type);
  });
}
function wireDetailEvents() {
  var backBtn = document.getElementById('btn_back');
  if (backBtn) backBtn.addEventListener('click', function () {
    currentView = 'list';
    renderAll(appsmith.model);
  });
  var closeBtn = document.getElementById('btn_close_pallet');
  if (closeBtn) closeBtn.addEventListener('click', function () {
    appsmith.updateModel({
      close_pallet: true
    });
    appsmith.triggerEvent('onClosePallet');
  });
  var addItemBtn = document.getElementById('btn_add_item');
  if (addItemBtn) addItemBtn.addEventListener('click', function () {
    selectedAsset = null;
    selectedPart = null;
    document.getElementById('f_description').value = '';
    document.getElementById('f_quantity').value = '1';
    document.getElementById('f_item_notes').value = '';
    document.getElementById('f_asset_search').value = '';
    document.getElementById('f_part_search').value = '';
