          '<button class="btn btn-close-pallet" id="btn_close_pallet">Close Pallet</button>' +
          '<button class="btn btn-secondary" id="btn_back">← Back</button>' +
        '</div>' +
      '</div>' +
      '<div class="meta-grid">' +
        '<div class="meta-item"><div class="meta-label">Vendor</div><div class="meta-value' + (p.vendor_name ? '' : ' muted') + '">' + escHtml(p.vendor_name || 'No vendor assigned') + '</div></div>' +
        '<div class="meta-item"><div class="meta-label">Weight</div><div class="meta-value">' + (p.weight_kg ? p.weight_kg + ' kg' : '—') + '</div></div>' +
        '<div class="meta-item"><div class="meta-label">Created</div><div class="meta-value">' + fmt(p.created_date) + '</div></div>' +
        '<div class="meta-item"><div class="meta-label">Collection Date</div><div class="meta-value">' + fmt(p.collection_date) + '</div></div>' +
      '</div>' +
    '</div>' +

    '<div class="card">' +
      '<div class="card-header"><span class="card-title">Items</span><button class="btn btn-primary" id="btn_add_item">+ Add Item</button></div>' +
      '<div class="form-panel" id="add_form">' +
        '<div class="form-title">Add Item</div>' +
        '<div class="type-tabs">' +
          '<button class="type-tab active" data-type="freetext">Free Text</button>' +
          '<button class="type-tab" data-type="asset">Asset</button>' +
          '<button class="type-tab" data-type="part">Part</button>' +
        '</div>' +
        '<div id="freetext_fields"><div class="form-grid">' +
          '<div class="form-group full"><label>Description</label><input type="text" id="f_description" placeholder="e.g. Mixed cables, power adapters"/></div>' +
          '<div class="form-group"><label>Quantity</label><input type="number" id="f_quantity" value="1" min="1"/></div>' +
          '<div class="form-group"><label>Notes</label><input type="text" id="f_item_notes"/></div>' +
        '</div></div>' +
        '<div id="asset_fields" style="display:none">' +
          '<div class="form-group full"><label>Search Asset</label><input type="text" id="f_asset_search" placeholder="Asset ref or serial..."/>' +
          '<div class="search-results" id="asset_results"></div><div class="selected-item" id="selected_asset_display"></div></div>' +
        '</div>' +
        '<div id="part_fields" style="display:none">' +
          '<div class="form-group full"><label>Search Part</label><input type="text" id="f_part_search" placeholder="Part ref or serial..."/>' +
          '<div class="search-results" id="part_results"></div><div class="selected-item" id="selected_part_display"></div></div>' +
        '</div>' +
        '<div class="form-actions"><button class="btn btn-secondary" id="btn_cancel_item">Cancel</button><button class="btn btn-primary" id="btn_save_item">Add to Pallet</button></div>' +
      '</div>' +
      '<table><thead><tr><th>Type</th><th>Reference</th><th>Description</th><th>Qty</th><th>Added By</th><th>Date</th><th></th></tr></thead>' +
      '<tbody>' + itemsRows + '</tbody></table>' +
    '</div>';
  }

  function setType(type) {
    currentType = type;
    ['freetext','asset','part'].forEach(function(t) {
      var el = document.getElementById(t + '_fields');
      if (el) el.style.display = t === type ? 'block' : 'none';
    });
    document.querySelectorAll('.type-tab').forEach(function(btn) {
      btn.classList.toggle('active', btn.dataset.type === type);
    });
  }

  function wireDetailEvents() {
    var backBtn = document.getElementById('btn_back');
    if (backBtn) backBtn.addEventListener('click', function() {
      currentView = 'list';
      renderAll(appsmith.model);
    });

    var closeBtn = document.getElementById('btn_close_pallet');
    if (closeBtn) closeBtn.addEventListener('click', function() {
      appsmith.updateModel({ close_pallet: true });
      appsmith.triggerEvent('onClosePallet');
    });

    var addItemBtn = document.getElementById('btn_add_item');
    if (addItemBtn) addItemBtn.addEventListener('click', function() {
      selectedAsset = null;
      selectedPart = null;
      document.getElementById('f_description').value = '';
      document.getElementById('f_quantity').value = '1';
      document.getElementById('f_item_notes').value = '';
      document.getElementById('f_asset_search').value = '';
      document.getElementById('f_part_search').value = '';
      document.getElementById('selected_asset_display').style.display = 'none';
      document.getElementById('selected_part_display').style.display = 'none';
      document.getElementById('asset_results').style.display = 'none';
      document.getElementById('part_results').style.display = 'none';
      setType('freetext');
      document.getElementById('add_form').classList.add('open');
    });

    var cancelItemBtn = document.getElementById('btn_cancel_item');
    if (cancelItemBtn) cancelItemBtn.addEventListener('click', function() {
      document.getElementById('add_form').classList.remove('open');
    });

    document.querySelectorAll('.type-tab').forEach(function(btn) {
      btn.addEventListener('click', function() { setType(this.dataset.type); });
    });

    var assetSearch = document.getElementById('f_asset_search');
    if (assetSearch) assetSearch.addEventListener('input', function() {
      var q = this.value;
      if (q.length < 2) { document.getElementById('asset_results').style.display = 'none'; return; }
      appsmith.updateModel({ search_query: q, search_type: 'asset' });
      appsmith.triggerEvent('onSearchAssets');
    });

    var partSearch = document.getElementById('f_part_search');
    if (partSearch) partSearch.addEventListener('input', function() {
      var q = this.value;
      if (q.length < 2) { document.getElementById('part_results').style.display = 'none'; return; }
      appsmith.updateModel({ search_query: q, search_type: 'part' });
      appsmith.triggerEvent('onSearchParts');
    });

    var saveItemBtn = document.getElementById('btn_save_item');
    if (saveItemBtn) saveItemBtn.addEventListener('click', function() {
      if (currentType === 'asset' && !selectedAsset) { alert('Please select an asset'); return; }
      if (currentType === 'part' && !selectedPart) { alert('Please select a part'); return; }
      appsmith.updateModel({
        item_type: currentType,
        item_asset_id: selectedAsset ? selectedAsset.asset_id : null,
        item_part_id: selectedPart ? selectedPart.id : null,
        item_description: document.getElementById('f_description').value,
        item_quantity: parseInt(document.getElementById('f_quantity').value) || 1,
        item_notes: document.getElementById('f_item_notes').value
      });
      appsmith.triggerEvent('onSaveItem');
      document.getElementById('add_form').classList.remove('open');
    });

    document.querySelectorAll('[data-action="delete-item"]').forEach(function(btn) {
      btn.addEventListener('click', function() {
        appsmith.updateModel({ delete_item_id: Number(this.dataset.itemId) });
        appsmith.triggerEvent('onDeleteItem');
      });
    });

    renderSearchResults(appsmith.model);
  }

  function renderSearchResults(model) {
    var ar = model.asset_results;
    var pr = model.part_results;
    var arEl = document.getElementById('asset_results');
    var prEl = document.getElementById('part_results');

    if (arEl && ar && ar.length) {
      arEl.style.display = 'block';
      arEl.innerHTML = ar.map(function(r, i) {
        return '<div class="search-result-row" data-asset-idx="' + i + '">' +
          '<span><span class="result-ref">' + escHtml(r.asset_ref) + '</span>' + escHtml([r.make_name, r.model_name].filter(Boolean).join(' ')) + '</span>' +
          '<span style="font-size:11px;color:#888780">' + escHtml(r.serial_number || '') + '</span></div>';
      }).join('');
      arEl.querySelectorAll('[data-asset-idx]').forEach(function(el) {
        el.addEventListener('click', function() {
          selectedAsset = (appsmith.model.asset_results || [])[Number(this.dataset.assetIdx)];
          if (!selectedAsset) return;
          var disp = document.getElementById('selected_asset_display');
          disp.textContent = selectedAsset.asset_ref + ' — ' + [selectedAsset.make_name, selectedAsset.model_name].filter(Boolean).join(' ');
          disp.style.display = 'block';
          arEl.style.display = 'none';
        });
      });
    } else if (arEl) {
      arEl.style.display = 'none';
    }

    if (prEl && pr && pr.length) {
      prEl.style.display = 'block';
      prEl.innerHTML = pr.map(function(r, i) {
        return '<div class="search-result-row" data-part-idx="' + i + '">' +
          '<span><span class="result-ref">' + escHtml(r.part_ref) + '</span>' + escHtml(r.part_type || '') + '</span>' +
          '<span style="font-size:11px;color:#888780">Grade ' + escHtml(r.condition_grade || '—') + '</span></div>';
      }).join('');
      prEl.querySelectorAll('[data-part-idx]').forEach(function(el) {
        el.addEventListener('click', function() {
          selectedPart = (appsmith.model.part_results || [])[Number(this.dataset.partIdx)];
          if (!selectedPart) return;
          var disp = document.getElementById('selected_part_display');
          disp.textContent = selectedPart.part_ref + ' — ' + (selectedPart.part_type || '') + (selectedPart.condition_grade ? ' Grade ' + selectedPart.condition_grade : '');
          disp.style.display = 'block';
          prEl.style.display = 'none';
        });
      });
    } else if (prEl) {
      prEl.style.display = 'none';
    }
  }

  // ---------- MAIN RENDER ----------
  function renderAll(model) {
    var m = model || {};
    pallets = m.pallets || [];
    vendors = m.vendors || [];
    items = m.items || [];

    if (currentView === 'detail') {
      var fresh = pallets.find(function(p) { return p.pallet_id === selectedPallet.pallet_id; });
      if (fresh) selectedPallet = fresh;
    }

    var root = document.getElementById('root');
    root.innerHTML = currentView === 'list' ? renderListView() : renderDetailView();

    if (currentView === 'list') wireListEvents();
    else wireDetailEvents();
  }

  function initWhenReady() {
    if (typeof appsmith === 'undefined' || !appsmith.onReady) {
      setTimeout(initWhenReady, 50);
      return;
    }
    appsmith.onReady(() => renderAll(appsmith.model));
    appsmith.onModelChange(() => renderAll(appsmith.model));
  }

  initWhenReady();
